part of '../view.dart';class _LoginButton extends StatelessWidget {  const _LoginButton({super.key});  @override  Widget build(BuildContext context) {    return ElevatedButton(      onPressed: () {        Navigator.of(context).pushReplacement(          MaterialPageRoute(builder: (context) => const HomeView()),        );      },      style: ButtonStyle(        backgroundColor: WidgetStatePropertyAll(AppColors.primary),        shape: WidgetStatePropertyAll(          RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),        ),        padding: WidgetStatePropertyAll(          const EdgeInsets.symmetric(vertical: 16),        ),        elevation: WidgetStatePropertyAll(1),        shadowColor: WidgetStatePropertyAll(AppColors.primary),      ),      child: Text(        'Login',        style: TextStyle(          fontSize: 16,          fontWeight: FontWeight.w400,          color: AppColors.white,        ),      ),    );  }}